     1→import { useNavigate, useLocation } from 'react-router-dom';
     2→import useKeyboardInset from '../../hooks/useKeyboardInset';
     3→
     4→const HIDDEN_PREFIXES = [
     5→  '/landing',
     6→  '/auth',
     7→  '/onboarding',
     8→  '/story',
     9→  '/comparison',
    10→  '/companies',
    11→  '/case',
    12→  '/notifications',
    13→  '/tutor',
    14→];
    15→const HIDDEN_EXACT = ['/'];
    16→
    17→const tabs = [
    18→  { id: 'portfolio', label: '투자', path: '/portfolio' },
    19→  { id: 'home', label: '홈', path: '/home' },
    20→  { id: 'education', label: '교육', path: '/education' },
    21→];
    22→
    23→const icons = {
    24→  home: (
    25→    <svg width="20" height="20" viewBox="0 0 24 24" fill="none" stroke="currentColor" strokeWidth="1.8" strokeLinecap="round" strokeLinejoin="round">
    26→      <path d="M3 9l9-7 9 7v11a2 2 0 0 1-2 2H5a2 2 0 0 1-2-2z" />
    27→      <polyline points="9 22 9 12 15 12 15 22" />
    28→    </svg>
    29→  ),
    30→  portfolio: (
    31→    <svg width="20" height="20" viewBox="0 0 24 24" fill="none" stroke="currentColor" strokeWidth="1.8" strokeLinecap="round" strokeLinejoin="round">
    32→      <path d="M4 18l6-6 4 4 6-8" />
    33→      <path d="M18 8h2v2" />
    34→    </svg>
    35→  ),
    36→  education: (
    37→    <svg width="20" height="20" viewBox="0 0 24 24" fill="none" stroke="currentColor" strokeWidth="1.8" strokeLinecap="round" strokeLinejoin="round">
    38→      <path d="m22 10-10-5-10 5 10 5 10-5z" />
    39→      <path d="M6 12v5c0 1.1 2.7 2 6 2s6-.9 6-2v-5" />
    40→    </svg>
    41→  ),
    42→};
    43→
    44→function isActivePath(tabPath, pathname, stateMode) {
    45→  if (tabPath === '/portfolio') {
    46→    if (pathname.startsWith('/agent')) return stateMode === 'stock';
    47→    return pathname === tabPath || pathname.startsWith('/portfolio/');
    48→  }
    49→
    50→  if (tabPath === '/home') {
    51→    if (pathname.startsWith('/agent')) return stateMode !== 'stock';
    52→    return pathname === tabPath;
    53→  }
    54→
    55→  return pathname === tabPath || pathname.startsWith('/education/');
    56→}
    57→
    58→export default function BottomNav() {
    59→  const navigate = useNavigate();
    60→  const location = useLocation();
    61→  const { shouldHideBottomNav } = useKeyboardInset();
    62→
    63→  if (
    64→    HIDDEN_EXACT.includes(location.pathname) ||
    65→    HIDDEN_PREFIXES.some((prefix) => location.pathname.startsWith(prefix)) ||
    66→    shouldHideBottomNav
    67→  ) {
    68→    return null;
    69→  }
    70→
    71→  const stateMode = location.pathname.startsWith('/agent') ? (location.state?.mode || 'home') : null;
    72→
    73→  return (
    74→    <nav className="fixed bottom-0 left-0 right-0 z-20 mx-auto h-[var(--bottom-nav-h,68px)] max-w-mobile border-t border-border bg-surface-elevated py-2">
    75→      <div className="flex justify-around">
    76→        {tabs.map((tab) => {
    77→          const isActive = isActivePath(tab.path, location.pathname, stateMode);
    78→
    79→          return (
    80→            <button
    81→              key={tab.id}
    82→              onClick={() => navigate(tab.path)}
    83→              className={`relative flex flex-col items-center gap-0.5 py-1 px-2 transition-colors ${
    84→                isActive ? 'text-primary' : 'text-[#364153]'
    85→              }`}
    86→            >
    87→              {icons[tab.id]}
