   384→                  <path d="M12 3l2 5 5 2-5 2-2 5-2-5-5-2 5-2 2-5z" />
   385→                  <path d="M19 4l.7 1.6 1.6.7-1.6.7-.7 1.6-.7-1.6-1.6-.7 1.6-.7.7-1.6z" />
   386→                  <path d="M5.5 15l.7 1.6 1.6.7-1.6.7-.7 1.6-.7-1.6-1.6-.7 1.6-.7.7-1.6z" />
   387→                </svg>
   388→              </button>
   389→
   390→              <input
   391→                type="text"
   392→                value={input}
   393→                onChange={(event) => {
   394→                  const val = event.target.value;
   395→                  setInput(val);
   396→                  if (val.startsWith('/')) {
